class Retangulo:
    def __init__(self, largura, altura):
        self.largura = largura
        self.altura  = altura

    def area(self):
        return self.largura * self.altura

    def perimetro(self):
        return 2 * (self.largura + self.altura)

    def __str__(self):
        return f'Retangulo(largura={self.largura}, altura={self.altura})'

r = Retangulo(4, 3)
print(r.area())
print(r.perimetro())
r2 = Retangulo(5, 2)
print(str(r2))
